namespace BgControls.Windows.Input.Touch;/// <summary>/// 手势管理器类，负责手势识别器工厂的注册、手势冲突解决以及手势状态转换的管理./// </summary>public static class GestureManager{    /// <summary>    /// 已注册的手势识别器工厂列表.    /// </summary>    private static List<IGestureRecognizerFactory> registeredGestureFactories = new List<IGestureRecognizerFactory>();    /// <summary>    /// 允许的手势转换映射表，键为当前手势名称，值为允许转换到的手势集合.    /// </summary>    private static Dictionary<string, HashSet<string>> allowedGestureTransitions = new Dictionary<string, HashSet<string>>();    /// <summary>    /// 按优先级排序后的手势识别器工厂缓存列表.    /// </summary>    private static List<IGestureRecognizerFactory>? prioritizedGestureFactories;    /// <summary>    /// Initializes static members of the <see cref="GestureManager"/> class.    /// </summary>    static GestureManager()    {        // 初始化集合对象.        GestureManager.registeredGestureFactories = new List<IGestureRecognizerFactory>();        GestureManager.allowedGestureTransitions = new Dictionary<string, HashSet<string>>();        // 注册系统预设的手势工厂.        GestureManager.RegisterGestureRecognizerFactory(new DragGestureRecognizerFactory());        GestureManager.RegisterGestureRecognizerFactory(new PinchGestureRecognizerFactory());        GestureManager.RegisterGestureRecognizerFactory(new SwipeGestureRecognizerFactory());        GestureManager.RegisterGestureRecognizerFactory(new TapGestureRecognizerFactory());    }    /// <summary>    /// 获取指定元素当前处于活动状态的手势名称.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <returns>活动手势的名称.</returns>    public static string GetActiveGesture(UIElement element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        // 获取冲突管理器并查询当前活动手势.        var conflictManager = GestureManager.GetOrCreateGestureConflictManager(element);        if (conflictManager != null)        {            return conflictManager.GetActiveGestureName();        }        return string.Empty;    }    /// <summary>    /// 判断指定元素是否可以激活目标手势.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <param name="candidateGestureName">候选手势名称.</param>    /// <returns>如果可以激活则返回 true; 否则返回 false.</returns>    public static bool CanActivateGesture(UIElement element, string candidateGestureName)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        var conflictManager = GestureManager.GetOrCreateGestureConflictManager(element);        if (conflictManager != null)        {            return conflictManager.CanActivateGesture(candidateGestureName);        }        return false;    }    /// <summary>    /// 激活指定元素的手势.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <param name="gestureName">手势名称.</param>    /// <param name="forcedFinish">当手势被强制结束时的回调动作.</param>    /// <returns>手势停用令牌.</returns>    public static GestureDeactivationToken? ActivateGesture(UIElement element, string gestureName, Action forcedFinish)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        var conflictManager = GestureManager.GetOrCreateGestureConflictManager(element);        if (conflictManager != null)        {            return conflictManager.ActivateGesture(element, gestureName, forcedFinish);        }        return null;    }    /// <summary>    /// 获取所有已注册的手势识别器工厂列表（按优先级排序）.    /// </summary>    /// <returns>工厂列表的副本.</returns>    public static IList<IGestureRecognizerFactory> GetRegisteredGestureRecognizerFactories()    {        // 如果缓存为空，则重新生成排序后的列表.        if (GestureManager.prioritizedGestureFactories == null)        {            GestureManager.prioritizedGestureFactories = GestureManager.registeredGestureFactories                .OrderBy(factory => factory.Priority)                .ToList();        }        return new List<IGestureRecognizerFactory>(GestureManager.prioritizedGestureFactories);    }    /// <summary>    /// 注册新的手势识别器工厂.    /// </summary>    /// <param name="gestureFactory">手势工厂实例.</param>    public static void RegisterGestureRecognizerFactory(IGestureRecognizerFactory gestureFactory)    {        ArgumentNullException.ThrowIfNull(gestureFactory, nameof(gestureFactory));        registeredGestureFactories.Add(gestureFactory);        // 调用工厂的转换注册逻辑.        gestureFactory.RegisterGestureTransitions();        // 重置优先级缓存.        prioritizedGestureFactories = null;    }    /// <summary>    /// 注销指定的手势识别器工厂.    /// </summary>    /// <param name="gestureFactory">手势工厂实例.</param>    public static void DeregisterGestureRecognizerFactory(IGestureRecognizerFactory gestureFactory)    {        ArgumentNullException.ThrowIfNull(gestureFactory, nameof(gestureFactory));        registeredGestureFactories.Remove(gestureFactory);        prioritizedGestureFactories = null;    }    /// <summary>    /// 检查两个手势之间是否允许进行转换.    /// </summary>    /// <param name="activeGestureName">当前活动手势.</param>    /// <param name="candidateGestureName">待激活的候选手势.</param>    /// <returns>如果允许转换则返回 true; 否则返回 false.</returns>    public static bool IsGestureTransitionAllowed(string activeGestureName, string candidateGestureName)    {        // 获取当前手势允许的所有转换集合并判断是否包含候选手势.        HashSet<string>? transitionSet = GetRegisteredGestureTransitions(activeGestureName) as HashSet<string>;        return transitionSet?.Contains(candidateGestureName) ?? false;    }    /// <summary>    /// 获取指定手势已注册的所有转换目标.    /// </summary>    /// <param name="gestureName">手势名称.</param>    /// <returns>允许转换到的手势名称枚举.</returns>    public static IEnumerable<string>? GetRegisteredGestureTransitions(string gestureName)    {        allowedGestureTransitions.TryGetValue(gestureName, out HashSet<string>? transitionSet);        return transitionSet;    }    /// <summary>    /// 注册手势转换规则.    /// </summary>    /// <param name="gestureName">源手势名称.</param>    /// <param name="transitions">允许转换到的目标手势序列.</param>    public static void RegisterGestureTransitions(string gestureName, IEnumerable<string> transitions)    {        ArgumentNullException.ThrowIfNull(gestureName, nameof(gestureName));        ArgumentNullException.ThrowIfNull(transitions, nameof(transitions));        // 转换为 HashSet 以提高查询性能.        if (transitions is not HashSet<string> transitionSet)        {            transitionSet = new HashSet<string>(transitions);        }        allowedGestureTransitions[gestureName] = transitionSet;    }    /// <summary>    /// 获取或创建指定元素的手势识别器.    /// </summary>    /// <typeparam name="T">手势识别器类型.</typeparam>    /// <param name="element">UI 元素.</param>    /// <returns>识别器实例.</returns>    public static T? GetOrCreateGestureRecognizer<T>(UIElement element)        where T : GestureRecognizerBase    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        var touchHelper = TouchManager.GetOrCreateTouchHelper(element);        if (touchHelper != null)        {            return touchHelper.GetOrCreateGestureHelper()?.GetRecognizer<T>();        }        return null;    }    /// <summary>    /// 尝试获取指定元素的手势识别器（不自动创建）.    /// </summary>    /// <typeparam name="T">手势识别器类型.</typeparam>    /// <param name="element">UI 元素.</param>    /// <returns>识别器实例，若不存在则返回 null.</returns>    internal static T? TryGetGestureRecognizer<T>(UIElement element)        where T : GestureRecognizerBase    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        var touchHelper = TouchManager.TryGetTouchHelper(element);        if (touchHelper != null)        {            return touchHelper.GetOrCreateGestureHelper()?.GetRecognizer<T>();        }        return null;    }    /// <summary>    /// 主动停用指定的手势令牌.    /// </summary>    /// <param name="token">手势停用令牌.</param>    internal static void DeactivateGestureWillingly(GestureDeactivationToken token)    {        ArgumentNullException.ThrowIfNull(token, nameof(token));        var conflictManager = GetOrCreateGestureConflictManager(token.Element);        if (conflictManager != null)        {            conflictManager.DeactivateGestureWillingly(token);        }    }    /// <summary>    /// 获取或创建指定元素的手势辅助工具.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <returns>手势辅助工具实例.</returns>    internal static GestureHelper? GetOrCreateGestureHelper(UIElement element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        var touchHelper = TouchManager.GetOrCreateTouchHelper(element);        return touchHelper?.GetOrCreateGestureHelper()!;    }    /// <summary>    /// 获取或创建指定元素的手势冲突管理器.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <returns>冲突管理器实例.</returns>    private static GestureConflictManager? GetOrCreateGestureConflictManager(UIElement element)    {        // 如果手势辅助工具中的冲突解析器为空，则初始化.        var gestureHelper = GetOrCreateGestureHelper(element);        if (gestureHelper != null)        {            if (gestureHelper.GestureConflictResolver == null)            {                gestureHelper.GestureConflictResolver = new GestureConflictManager();            }            return gestureHelper.GestureConflictResolver;        }        return null;    }    /// <summary>    /// 为指定元素添加活动手势更改的事件处理程序.    /// </summary>    /// <param name="element">UI 元素.</param>    /// <param name="handler">事件处理程序.</param>    internal static void AddActiveGestureChangedEventHandler(UIElement element, EventHandler handler)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        ArgumentNullException.ThrowIfNull(handler, nameof(handler));        var conflictManager = GetOrCreateGestureConflictManager(element);        if (conflictManager != null)        {            conflictManager.ActiveGestureChanged += handler;        }    }}